worked_example.final_code:
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.util.stream.*;

class RequestAnalytics {
    private final ConcurrentHashMap<String, AtomicLong> requestCounts = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, AtomicLong> responseTimes = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, AtomicLong> errorCounts   = new ConcurrentHashMap<>();
    private final AtomicLong totalRequests = new AtomicLong(0);

    void recordRequest(String endpoint, long ms) {
        requestCounts.computeIfAbsent(endpoint, k -> new AtomicLong(0)).incrementAndGet();
        responseTimes.computeIfAbsent(endpoint, k -> new AtomicLong(0)).addAndGet(ms);
        totalRequests.incrementAndGet();
    }

    void recordError(String endpoint) {
        errorCounts.computeIfAbsent(endpoint, k -> new AtomicLong(0)).incrementAndGet();
    }

    List<String> getTopEndpoints(int n) {
        return requestCounts.entrySet().stream()
            .sorted((a, b) -> Long.compare(b.getValue().get(), a.getValue().get()))
            .limit(n).map(Map.Entry::getKey).collect(Collectors.toList());
    }

    double getAvgMs(String ep) {
        AtomicLong t = responseTimes.get(ep), c = requestCounts.get(ep);
        return (t==null||c==null||c.get()==0) ? 0 : (double)t.get()/c.get();
    }
}

public class AnalyticsDemo {
    public static void main(String[] args) throws InterruptedException {
        RequestAnalytics analytics = new RequestAnalytics();
        String[] endpoints = {"/api/orders", "/api/users", "/api/products", "/api/search"};

        ExecutorService pool = Executors.newFixedThreadPool(8);
        Random rnd = new Random();

        // Simulate 1000 concurrent requests:
        for (int i = 0; i < 1000; i++) {
            String ep = endpoints[i % endpoints.length];
            pool.submit(() -> {
                analytics.recordRequest(ep, 10 + rnd.nextInt(200));
                if (rnd.nextInt(10) == 0) analytics.recordError(ep);
            });
        }
        pool.shutdown();
        pool.awaitTermination(10, TimeUnit.SECONDS);

        System.out.println("Total requests: " + analytics.totalRequests.get());
        System.out.println("Top endpoints:");
        analytics.getTopEndpoints(4).forEach(ep ->
            System.out.printf("  %-20s %s reqs, avg %.0fms%n",
                ep,
                analytics.requestCounts.get(ep).get(),
                analytics.getAvgMs(ep)));
    }
}
